steps.body:
Se você marca uma função como async:

async function exemplo() {
  return 10;
}

Mesmo retornando 10, ela retorna uma Promise que resolve 10.

exemplo().then(console.log) // 10

Regra:
- async embrulha o return em Promise.

Se você tem uma promise:

const p = Promise.resolve('ok');

Com then:
p.then((v) => console.log(v));

Com await:
async function rodar() {
  const v = await p;
  console.log(v);
}
rodar();

await pega o valor resolvido.

Se a promise rejeitar:
- await lança erro (como throw)
- você trata com try/catch.

Antes (then):
fetch(url)
  .then(res => {
    if (!res.ok) throw new Error('HTTP ' + res.status);
    return res.json();
  })
  .then(data => ...)
  .catch(err => ...)

Agora (async/await):

async function carregar() {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const data = await res.json();
    // sucesso
  } catch (err) {
    // erro
  }
}

Você vê o fluxo claramente:
- request → checa ok → parse → usa data.

extra.modelJs:
/* Aula 31 — modelJs: fetch com async/await + UI */

const btn = document.querySelector('#carregar');
const statusEl = document.querySelector('#status');
const saida = document.querySelector('#saida');

function setStatus(txt) {
  if (statusEl) statusEl.textContent = txt;
}

function setSaida(obj) {
  if (!saida) return;
  saida.textContent = obj ? JSON.stringify(obj, null, 2) : '';
}

async function carregarTodo() {
  if (!btn) return;

  setStatus('Carregando...');
  setSaida(null);
  btn.disabled = true;

  try {
    const res = await fetch('https://jsonplaceholder.typicode.com/todos/1');
    if (!res.ok) throw new Error(`HTTP ${res.status}`);

    const data = await res.json();
    setStatus('OK');
    setSaida(data);
  } catch (err) {
    setStatus(`Erro: ${err.message}`);
  } finally {
    btn.disabled = false;
  }
}

if (btn) {
  btn.addEventListener('click', carregarTodo);
}
